content.text:
프로젝트 구조 파악이 완료되었습니다. 이제 GraphQL 스킬과 gRPC 스킬의 컨벤션을 기반으로 프로필 수정 API 인터페이스를 설계합니다.

---

# 프로필 수정 API 인터페이스 설계

## 1. 현재 구조 분석 결과

SKILL.md 파일과 프로젝트 컨벤션을 바탕으로 다음을 확인했습니다.

| 항목 | 내용 |
|------|------|
| GraphQL 파일 위치 | `graphql/src/main/resources/graphql/` |
| Proto 파일 위치 | `protobuf/src/main/proto/profile/` |
| Entity Catalog | `maum` (profile 도메인) |
| 인증 방식 | `@PreAuthorize("hasAuthority('User')")` + `@UserId` |
| 에러 처리 | `CustomGraphQLException` |
| 부분 업데이트 | `optional` 필드로 지원 |

---

## 2. GraphQL 스키마 설계

파일 경로: `graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# ──────────────────────────────────────────
# 공통 열거형
# ──────────────────────────────────────────

"""사용자 성별"""
enum Gender {
    MALE
    FEMALE
    NON_BINARY
    PREFER_NOT_TO_SAY
}

"""선호 언어 코드 (IETF BCP 47 기반)"""
enum LanguageCode {
    KO  # 한국어
    EN  # 영어
    JA  # 일본어
    ZH  # 중국어
}

# ──────────────────────────────────────────
# 타입 정의
# ──────────────────────────────────────────

"""위치 정보"""
type Location {
    """위도 (-90.0 ~ 90.0)"""
    latitude: Float!
    """경도 (-180.0 ~ 180.0)"""
    longitude: Float!
    """국가 코드 (ISO 3166-1 alpha-2, 예: KR)"""
    countryCode: String!
    """도시명"""
    city: String
    """표시용 위치 레이블 (예: 서울 강남구)"""
    displayName: String
}

"""관심사/태그"""
type Interest {
    """태그 식별자"""
    id: ID!
    """태그 라벨 (예: 독서, 음악)"""
    label: String!
}

"""프로필 정보"""
type Profile {
    """사용자 식별자"""
    userId: ID!
    """닉네임 (2~20자)"""
    nickname: String!
    """자기소개 (최대 300자)"""
    bio: String
    """프로필 사진 URL"""
    profileImageUrl: String
    """생년월일 (ISO 8601, 예: 1995-03-15)"""
    birthDate: String
    """성별"""
    gender: Gender
    """위치 정보"""
    location: Location
    """관심사 목록 (최대 10개)"""
    interests: [Interest!]!
    """선호 언어 목록"""
    languages: [LanguageCode!]!
    """프로필 마지막 수정 일시 (ISO 8601)"""
    updatedAt: String!
}

# ──────────────────────────────────────────
# 입력 타입 정의 (부분 업데이트 지원)
# ──────────────────────────────────────────

"""위치 정보 입력"""
input LocationInput {
    """위도 (-90.0 ~ 90.0)"""
    latitude: Float!
    """경도 (-180.0 ~ 180.0)"""
    longitude: Float!
    """국가 코드 (ISO 3166-1 alpha-2)"""
    countryCode: String!
    """도시명"""
    city: String
}

"""
프로필 수정 입력 (Partial Update 지원)
- null 인 필드는 변경하지 않음
- 명시적으로 빈 문자열("")을 전달하면 해당 필드를 초기화
"""
input UpdateProfileInput {
    """닉네임 (2~20자, null이면 변경 안 함)"""
    nickname: String

    """자기소개 (최대 300자, null이면 변경 안 함, 빈 문자열이면 초기화)"""
    bio: String

    """
    프로필 사진 업로드 후 받은 S3 object key
    null이면 변경 안 함, 빈 문자열이면 사진 삭제
    """
    profileImageKey: String

    """생년월일 (ISO 8601 형식, 예: 1995-03-15)"""
    birthDate: String

    """성별"""
    gender: Gender

    """위치 정보 (null이면 변경 안 함)"""
    location: LocationInput

    """관심사 ID 목록 (null이면 변경 안 함, 빈 배열이면 전체 삭제, 최대 10개)"""
    interestIds: [ID!]

    """선호 언어 목록 (null이면 변경 안 함, 빈 배열이면 전체 삭제)"""
    languages: [LanguageCode!]
}

# ──────────────────────────────────────────
# Mutation / Query 정의
# ──────────────────────────────────────────

extend type Query {
    """내 프로필 조회"""
    myProfile: Profile!
}

extend type Mutation {
    """
    프로필 수정 (Partial Update)
    - 전달한 필드만 업데이트
    - 인증 필요
    """
    updateProfile(input: UpdateProfileInput!): Profile!

    """
    프로필 사진 삭제
    - updateProfile(input: { profileImageKey: "" }) 의 편의 Mutation
    """
    deleteProfileImage: Profile!
}
```

---

## 3. gRPC Proto 설계

파일 경로: `protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ──────────────────────────────────────────
// 열거형 정의
// ──────────────────────────────────────────

// 성별
enum Gender {
    GENDER_UNSPECIFIED = 0;
    GENDER_MALE = 1;
    GENDER_FEMALE = 2;
    GENDER_NON_BINARY = 3;
    GENDER_PREFER_NOT_TO_SAY = 4;
}

// 언어 코드 (IETF BCP 47 기반)
enum LanguageCode {
    LANGUAGE_UNSPECIFIED = 0;
    LANGUAGE_KO = 1;  // 한국어
    LANGUAGE_EN = 2;  // 영어
    LANGUAGE_JA = 3;  // 일본어
    LANGUAGE_ZH = 4;  // 중국어
}

// ──────────────────────────────────────────
// 공통 메시지 타입
// ──────────────────────────────────────────

// 위치 정보
message Location {
    double latitude = 1;   // 위도
    double longitude = 2;  // 경도
    string country_code = 3; // 국가 코드 (ISO 3166-1 alpha-2)
    string city = 4;         // 도시명
    string display_name = 5; // 표시용 위치 레이블
}

// 관심사/태그
message Interest {
    string id = 1;     // 태그 식별자
    string label = 2;  // 태그 라벨
}

// 프로필 전체 데이터
message Profile {
    string user_id = 1;           // 사용자 식별자
    string nickname = 2;          // 닉네임
    string bio = 3;               // 자기소개
    string profile_image_url = 4; // 프로필 사진 URL
    string birth_date = 5;        // 생년월일 (ISO 8601)
    Gender gender = 6;            // 성별
    Location location = 7;        // 위치 정보
    repeated Interest interests = 8; // 관심사 목록
    repeated LanguageCode languages = 9; // 선호 언어 목록
    string updated_at = 10;       // 마지막 수정 일시 (ISO 8601)
}

// ──────────────────────────────────────────
// 부분 업데이트용 FieldMask 패턴 적용
// ──────────────────────────────────────────

// 프로필 업데이트 필드 마스크
// - 포함된 필드명만 서버에서 업데이트 처리
// - proto3에서 optional 필드 부분 업데이트를 명시적으로 제어하기 위해 사용
message ProfileFieldMask {
    bool nickname = 1;
    bool bio = 2;
    bool profile_image_key = 3;
    bool birth_date = 4;
    bool gender = 5;
    bool location = 6;
    bool interest_ids = 7;
    bool languages = 8;
}

// ──────────────────────────────────────────
// Request / Response 메시지
// ──────────────────────────────────────────

// 프로필 조회 요청
message GetProfileRequest {
    string user_id = 1; // 조회 대상 사용자 ID
}

// 프로필 조회 응답
message GetProfileResponse {
    Profile profile = 1;
}

// 프로필 수정 요청
message UpdateProfileRequest {
    string user_id = 1;              // 수정 요청자 ID (인증된 사용자)

    // 변경할 값 (선택 필드)
    optional string nickname = 2;           // 닉네임 (2~20자)
    optional string bio = 3;                // 자기소개 (최대 300자, 빈 문자열 = 초기화)
    optional string profile_image_key = 4;  // S3 object key (빈 문자열 = 삭제)
    optional string birth_date = 5;         // 생년월일 (ISO 8601)
    optional Gender gender = 6;             // 성별
    optional Location location = 7;         // 위치 정보

    // 목록형 필드는 has_* 플래그로 "빈 배열 전달 vs 변경 없음" 구분
    bool has_interest_ids = 8;              // true이면 interest_ids 반영
    repeated string interest_ids = 9;       // 관심사 ID 목록 (최대 10개)

    bool has_languages = 10;                // true이면 languages 반영
    repeated LanguageCode languages = 11;   // 선호 언어 목록

    // 업데이트할 필드를 명시 (FieldMask 패턴)
    ProfileFieldMask update_mask = 12;
}

// 프로필 수정 응답
message UpdateProfileResponse {
    Profile profile = 1; // 수정 후 최신 프로필
}

// 프로필 사진 삭제 요청
message DeleteProfileImageRequest {
    string user_id = 1;
}

// 프로필 사진 삭제 응답
message DeleteProfileImageResponse {
    Profile profile = 1;
}

// ──────────────────────────────────────────
// 서비스 정의
// ──────────────────────────────────────────

service ProfileService {
    // 프로필 조회 (단일 사용자)
    rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);

    // 프로필 수정 (Partial Update)
    rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);

    // 프로필 사진 삭제
    rpc DeleteProfileImage(DeleteProfileImageRequest) returns (DeleteProfileImageResponse);
}
```

