## 4. GraphQL Controller 구현 예시

파일 경로: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileGrpcService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.getProfile(userId)
        return response.profile.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): ProfileResponse {
        val response = profileService.updateProfile(userId, input)
        return response.profile.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteProfileImage(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.deleteProfileImage(userId)
        return response.profile.toResponse()
    }
}
```

파일 경로: `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileGrpcService.kt`

```kotlin
@Service
class ProfileGrpcService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getProfile(userId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val maskBuilder = ProfileFieldMask.newBuilder()
        val requestBuilder = UpdateProfileRequest.newBuilder().setUserId(userId)

        // null이 아닌 필드만 포함 (Partial Update)
        input.nickname?.let {
            requestBuilder.setNickname(it)
            maskBuilder.setNickname(true)
        }
        input.bio?.let {
            requestBuilder.setBio(it)
            maskBuilder.setBio(true)
        }
        input.profileImageKey?.let {
            requestBuilder.setProfileImageKey(it)
            maskBuilder.setProfileImageKey(true)
        }
        input.birthDate?.let {
            requestBuilder.setBirthDate(it)
            maskBuilder.setBirthDate(true)
        }
        input.gender?.let {
            requestBuilder.setGender(it.toProto())
            maskBuilder.setGender(true)
        }
        input.location?.let {
            requestBuilder.setLocation(it.toProto())
            maskBuilder.setLocation(true)
        }
        input.interestIds?.let {
            requestBuilder.setHasInterestIds(true)
            requestBuilder.addAllInterestIds(it)
            maskBuilder.setInterestIds(true)
        }
        input.languages?.let {
            requestBuilder.setHasLanguages(true)
            requestBuilder.addAllLanguages(it.map { lang -> lang.toProto() })
            maskBuilder.setLanguages(true)
        }

        requestBuilder.setUpdateMask(maskBuilder.build())

        return try {
            stub.updateProfile(requestBuilder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun deleteProfileImage(userId: String): DeleteProfileImageResponse {
        val request = DeleteProfileImageRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.deleteProfileImage(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

